import os
import datetime
import requests
import json
import pandas as pd
from typing import Any
from pyspark.sql import SparkSession, DataFrame
from pyspark.sql.types import *

# -------------------------------------------------------------------------
# Mocking WorkflowContext for local execution
# -------------------------------------------------------------------------
try:
    from fire.workflowcontext import WorkflowContext
except ImportError:
    class WorkflowContext:
        def outStr(self, level, message, msg_type):
            print(f"[{msg_type}] {message}")

# -------------------------------------------------------------------------
# Helper Functions
# -------------------------------------------------------------------------

def get_all_workflows(fire_host, headers):
    """Fetch ALL workflows in the system."""
    r = requests.get(f"{fire_host}/api/v1/workflows/all", headers=headers)
    r.raise_for_status()
    return r.json()

def get_last_workflow_execution(fire_host, workflow_id, headers):
    """Fetch the last execution status of a specific workflow."""
    r = requests.get(f"{fire_host}/api/v1/last/workflow-execution/{workflow_id}", headers=headers)

    if r.status_code != 200:
        return {}

    if not r.text.strip():
        return {}

    try:
        return r.json()
    except ValueError:
        return {}

def _status_label(raw_status: Any) -> str:
    STATUS_MAP = {
        0: "RUNNING", 1: "STOPPED", 2: "COMPLETED", 3: "FAILED",
        4: "STARTING", 5: "STOP", 6: "KILLED", 7: "STOPPING",
        8: "TIMEOUT", 9: "PENDING", 10: "SKIPPED",
    }
    if raw_status is None: return ""
    try:
        code = int(raw_status)
        return STATUS_MAP.get(code, str(raw_status))
    except (TypeError, ValueError):
        return str(raw_status)

def _convert_to_readable_time(ms_timestamp: int) -> str:
    if ms_timestamp is None: return ""
    try:
        timestamp_seconds = ms_timestamp / 1000
        return datetime.datetime.fromtimestamp(timestamp_seconds).strftime('%Y-%m-%d %H:%M:%S')
    except Exception as e:
        return str(ms_timestamp)

# -------------------------------------------------------------------------
# Main Logic Function
# -------------------------------------------------------------------------

def myfn(spark: SparkSession, workflowContext: WorkflowContext, id: int, inDF: DataFrame, cust_dict: dict):

    # --- CONFIGURATION -------------------------------------------------------
    fire_host = '${fire_host}'.rstrip("/")
    api_token = '${api_token}'

    # Supported formats include:
    #   '14788','14865'
    #   "none"
    project_ids_str = "${project_ids_str}"
    # -------------------------------------------------------------------------

    headers = {
        "token": api_token,
        "Accept": "application/json",
    }

    output_schema = StructType([
        StructField("workflowId", StringType(), True),
        StructField("workflowName", StringType(), True),
        StructField("projectId", StringType(), True),
        StructField("status", StringType(), True),
        StructField("startTime", StringType(), True),
        StructField("endTime", StringType(), True),
        StructField("username", StringType(), True)
    ])

    try:
        # 1. Fetch ALL workflows first
        print(f"Fetching ALL workflows from {fire_host}...")
        all_workflows = get_all_workflows(fire_host, headers)
        print(f"Total workflows in system: {len(all_workflows)}")

        # 2. Parse Project ID Filter
        target_project_ids = set()
        clean_input = (project_ids_str.strip()
                       .replace('(', '').replace(')', '')
                       .replace('[', '').replace(']', '')
                       .replace("'", "").replace('"', '')
                       .replace(':', ','))

        if clean_input and clean_input.lower() != "none":
            try:
                target_project_ids = {int(pid.strip()) for pid in clean_input.split(',') if pid.strip()}
                print(f"Filtering for Project IDs: {target_project_ids}")
            except ValueError:
                print("Error: project_ids_str contains non-numeric values. Ignoring filter and fetching ALL.")
                target_project_ids = set()
        else:
            print("Project filter is empty or 'none'. Fetching ALL workflows.")

        rows = []

        # 3. Iterate and Filter
        for wf in all_workflows:
            wf_id = wf.get("id")
            wf_name = wf.get("name", "")
            wf_project_id = wf.get("projectId") 

            if wf_id is None:
                continue

            # --- FILTER LOGIC ---
            if target_project_ids:
                try:
                    p_id_int = int(wf_project_id) if wf_project_id is not None else -1
                except ValueError:
                    p_id_int = -1

                if p_id_int not in target_project_ids:
                    continue 
            # --------------------

            try:
                # Get the last execution for this specific workflow
                exec_data = get_last_workflow_execution(fire_host, wf_id, headers)

                row = {
                    "workflowId": str(wf_id),
                    "workflowName": str(wf_name),
                    "projectId": str(wf_project_id) if wf_project_id is not None else "",
                    "status": "",
                    "startTime": "",
                    "endTime": "",
                    "username": ""
                }

                if exec_data:
                    row["status"] = _status_label(exec_data.get("status"))
                    row["startTime"] = _convert_to_readable_time(exec_data.get("startTime"))
                    row["endTime"] = _convert_to_readable_time(exec_data.get("endTime"))
                    row["username"] = str(exec_data.get("username") or "")

                rows.append(row)

            except Exception as inner_e:
                print(f"Warning: Unexpected error for workflow ID {wf_id}: {inner_e}")
                rows.append({
                    "workflowId": str(wf_id),
                    "workflowName": str(wf_name),
                    "projectId": str(wf_project_id) if wf_project_id is not None else "",
                    "status": "ERROR",
                    "startTime": "",
                    "endTime": "",
                    "username": ""
                })

        # 4. Create DataFrame
        if not rows:
            print("No rows generated (Filter matched nothing or no workflows found).")
            outDF = spark.createDataFrame([], schema=output_schema)
        else:
            df = pd.DataFrame(rows)
            outDF = spark.createDataFrame(df)

        return outDF

    except Exception as e:
        error_msg = f"Failed to extract workflow data: {str(e)}"
        workflowContext.outStr(3, error_msg, "Error")
        print(f"CRITICAL ERROR: {error_msg}")

        outDF = spark.createDataFrame([], schema=output_schema)
        return outDF
